import React, { useState, useEffect, useCallback } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';

// Mock components for sections
const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);

  // Selection state for bulk actions
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
  const [selectedIndicacoes, setSelectedIndicacoes] = useState<string[]>([]);

  // Modals state
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => u.login === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  const getFilteredVendas = () => {
    if (!user) return [];
    return user.isAdmin ? vendas : vendas.filter(v => v.vendedor === user.nome);
  };

  const getFilteredIndicacoes = () => {
    if (!user) return [];
    return user.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user.nome);
  };

  const toggleVendaSelection = (id: string) => {
    setSelectedVendas(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const toggleIndicacaoSelection = (id: string) => {
    setSelectedIndicacoes(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const handleBulkDelete = async (type: 'vendas' | 'indicacoes') => {
    if (confirm("Deseja realmente excluir os itens selecionados?")) {
      const targets = type === 'vendas' ? selectedVendas : selectedIndicacoes;
      for (const id of targets) {
        await cloud.apagar(type, id);
      }
      if (type === 'vendas') setSelectedVendas([]);
      else setSelectedIndicacoes([]);
    }
  };

  // Sections
  const Dashboard = () => {
    const myV = getFilteredVendas();
    const today = new Date().setHours(0, 0, 0, 0);
    const vHoje = myV.filter(v => v.dataCriacao >= today);

    const vendasHojeCount = vHoje.length;
    const comissaoHoje = vHoje.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);
    const premioHoje = vHoje.reduce((a, b) => a + Number(b.valor || 0), 0);

    const targets = user?.isAdmin ? usuarios : [user!];

    return (
      <div className="animate-in fade-in duration-300">
        <h2 className="text-2xl font-bold uppercase mb-8 text-white tracking-tighter">Performance Hoje</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          <div className="bg-[#111827] p-6 rounded-2xl border border-blue-900/30 text-center">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">Vendas Hoje</p>
            <h2 className="text-4xl font-bold text-white">{vendasHojeCount}</h2>
          </div>
          <div className="bg-[#111827] p-6 rounded-2xl border border-green-900/30 text-center">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">Comissão Hoje</p>
            <h2 className="text-4xl font-bold text-green-500">{FORMAT_BRL(comissaoHoje)}</h2>
          </div>
          <div className="bg-[#111827] p-6 rounded-2xl border border-gray-800 text-center">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">Prêmio Líquido Hoje</p>
            <h2 className="text-4xl font-bold text-white">{FORMAT_BRL(premioHoje)}</h2>
          </div>
        </div>

        <h2 className="text-2xl font-bold uppercase mb-8 text-white tracking-tighter">Acompanhamento de Metas</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {targets.map(u => {
            const meta = metas.find(m => m.vendedor === u.nome) || { meta_salario: 0, meta_premio: 0 };
            const userVendas = vendas.filter(v => v.vendedor === u.nome && v.status === 'Pagamento Efetuado');
            const realC = userVendas.reduce((a, b) => a + Number(b.comissao_vendedor || 0), 0);
            const realP = userVendas.reduce((a, b) => a + Number(b.valor || 0), 0);
            const pC = Math.min((realC / (meta.meta_salario || 1)) * 100, 100);
            const pP = Math.min((realP / (meta.meta_premio || 1)) * 100, 100);

            return (
              <div key={u.id || u.nome} className="bg-[#111827] p-6 rounded-3xl border border-gray-800">
                <h4 className="text-xs font-bold uppercase text-blue-400 mb-4">{u.nome}</h4>
                <div className="space-y-4">
                  <div>
                    <p className="text-[9px] text-gray-500 uppercase mb-1">Salário: {FORMAT_BRL(realC)} / {FORMAT_BRL(meta.meta_salario)}</p>
                    <div className="bg-[#1e293b] rounded-2xl h-3 w-full overflow-hidden border border-gray-700">
                      <div className="bg-gradient-to-r from-blue-500 to-green-500 h-full transition-all duration-500" style={{ width: `${pC}%` }}></div>
                    </div>
                  </div>
                  <div>
                    <p className="text-[9px] text-gray-500 uppercase mb-1">Prêmio: {FORMAT_BRL(realP)} / {FORMAT_BRL(meta.meta_premio)}</p>
                    <div className="bg-[#1e293b] rounded-2xl h-3 w-full overflow-hidden border border-gray-700">
                      <div className="bg-gradient-to-r from-blue-500 to-green-500 h-full transition-all duration-500" style={{ width: `${pP}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const KanbanIndicacoes = () => {
    const myInd = getFilteredIndicacoes();
    return (
      <div className="animate-in fade-in duration-300">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold uppercase text-blue-500 tracking-tighter">Fluxo de Indicações</h2>
          <div className="flex gap-2">
            <button 
              onClick={() => handleBulkDelete('indicacoes')}
              className="bg-red-600/20 text-red-500 border border-red-600/50 px-4 py-2 rounded-xl font-bold text-[10px] uppercase transition"
            >
              Excluir Selecionados
            </button>
            <button 
              onClick={() => { setModalType('indicacao'); setEditingItem(null); }}
              className="bg-yellow-600 px-6 py-2 rounded-xl font-bold text-[11px] uppercase text-black transition"
            >
              + Manual
            </button>
          </div>
        </div>
        <div className="flex gap-6 overflow-x-auto pb-4 scrollbar-thin">
          {INDICACAO_STATUS_MAP.map(status => (
            <div key={status} className="kanban-column bg-[#0f172a] rounded-2xl p-5 border border-gray-800">
              <h3 className="text-[11px] font-black mb-6 uppercase text-gray-400 text-center border-b border-gray-800 pb-4">{status}</h3>
              <div className="space-y-4 min-h-[400px]">
                {myInd.filter(i => i.status === status).map(i => (
                  <div key={i.id} className="relative group bg-[#1e293b] border border-gray-700 p-4 rounded-xl border-l-4 border-l-yellow-500 hover:scale-[1.02] transition-all cursor-pointer">
                    <input 
                      type="checkbox" 
                      className="absolute top-3 right-3 w-4 h-4 accent-red-500 z-10 cursor-pointer"
                      checked={selectedIndicacoes.includes(i.id!)}
                      onChange={() => toggleIndicacaoSelection(i.id!)}
                    />
                    <div onClick={() => { setModalType('indicacao'); setEditingItem(i); }}>
                      <h4 className="text-[11px] font-black uppercase text-white truncate pr-8">{i.cliente}</h4>
                      <p className="text-[10px] text-gray-300 uppercase mt-1 font-bold">{i.veiculo || 'NÃO INFORMADO'}</p>
                      {i.suhai && <span className="s-suhai-pulse text-[12px] block mt-1">S</span>}
                      <p className="text-[10px] text-blue-400 font-bold mt-2"><i className="fab fa-whatsapp text-green-500 mr-1"></i>{i.tel}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const KanbanVendas = () => {
    const myV = getFilteredVendas();
    return (
      <div className="animate-in fade-in duration-300">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold uppercase text-blue-500">Produção</h2>
          <div className="flex gap-2">
            <button 
              onClick={() => handleBulkDelete('vendas')}
              className="bg-red-600/20 text-red-500 border border-red-600/50 px-4 py-2 rounded-xl font-bold text-[10px] uppercase hover:bg-red-600 hover:text-white transition"
            >
              Excluir Selecionados
            </button>
            <button 
              onClick={() => { setModalType('venda'); setEditingItem(null); }}
              className="bg-blue-600 px-6 py-2 rounded-xl font-bold text-[11px] uppercase transition"
            >
              + Produção
            </button>
          </div>
        </div>
        <div className="flex gap-6 overflow-x-auto pb-4 scrollbar-thin">
          {VENDA_STATUS_MAP.map(status => (
            <div key={status} className="kanban-column bg-[#0f172a] rounded-2xl p-5 border border-gray-800">
              <h3 className="text-[11px] font-black mb-6 uppercase text-gray-400 text-center border-b border-gray-800 pb-4">{status}</h3>
              <div className="space-y-4 min-h-[400px]">
                {myV.filter(v => v.status === status).map(v => (
                  <div key={v.id} className="relative group bg-[#1e293b] border border-gray-700 p-4 rounded-xl border-l-4 border-l-blue-500 hover:scale-[1.02] transition-all cursor-pointer">
                    <input 
                      type="checkbox" 
                      className="absolute top-3 right-3 w-4 h-4 accent-red-500 z-10 cursor-pointer"
                      checked={selectedVendas.includes(v.id!)}
                      onChange={() => toggleVendaSelection(v.id!)}
                    />
                    <div onClick={() => { setModalType('venda'); setEditingItem(v); }}>
                      <div className="flex items-center gap-2 mb-2">
                        {v.suhai ? <i className="fas fa-star text-green-500 text-[10px]"></i> : <i className="fas fa-bell text-yellow-500 text-[10px]"></i>}
