                      </div>
                      <p className="text-[10px] text-blue-400 font-bold mb-3">{v.tel}</p>
                      <div className="bg-[#0f172a] border border-gray-700 p-2 rounded-lg text-center mb-2">
                        <span className="text-[7px] uppercase font-bold text-gray-500 block">Prêmio</span>
                        <span className="text-[11px] font-bold text-white">{FORMAT_BRL(v.valor)}</span>
                      </div>
                      <div className="flex gap-2">
                        <div className="flex-1 bg-[#0f172a] border border-gray-700 p-1 rounded-lg text-center">
                          <span className="text-[7px] uppercase font-bold text-blue-500 block">Cheia</span>
                          <span className="text-[10px] font-bold">{FORMAT_BRL(v.comissao_cheia)}</span>
                        </div>
                        <div className="flex-1 bg-[#0f172a] border border-gray-700 p-1 rounded-lg text-center">
                          <span className="text-[7px] uppercase font-bold text-green-500 block">Vend.</span>
                          <span className="text-[10px] font-bold">{FORMAT_BRL(v.comissao_vendedor)}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const Financeiro = () => {
    const concluido = getFilteredVendas().filter(v => v.status === 'Pagamento Efetuado');
    const totalComissao = concluido.reduce((a, b) => a + Number(user?.isAdmin ? b.comissao_cheia : b.comissao_vendedor), 0);
    const totalPremio = concluido.reduce((a, b) => a + Number(b.valor), 0);

    return (
      <div className="animate-in fade-in duration-300">
        <h2 className="text-2xl font-bold uppercase text-green-500 mb-8 tracking-tighter">Financeiro Realizado</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8 text-center">
          <div className="bg-[#111827] p-8 rounded-2xl border border-green-900/30">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">
              {user?.isAdmin ? "Comissão Empresa" : "Sua Comissão"}
            </p>
            <h2 className="text-5xl font-bold text-green-500">{FORMAT_BRL(totalComissao)}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-2xl border border-gray-800">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">Volume Líquido</p>
