      {activeSection === 'metas' && <MetasView />}
      {activeSection === 'lead-suhai-page' && <LeadSuhaiView />}
      {activeSection === 'links-uteis' && <LinksUteis />}
      {activeSection === 'configuracoes' && (
        <div className="animate-in fade-in duration-300">
           <h2 className="text-2xl font-bold uppercase text-gray-400 mb-8">Manutenção</h2>
           <button 
             onClick={async () => { if(confirm("Zerar tudo?")) { for(let v of vendas) await cloud.apagar('vendas', v.id!); } }}
             className="bg-red-600/10 text-red-500 border border-red-600 p-4 rounded-xl font-bold text-[10px] uppercase transition hover:bg-red-600 hover:text-white"
           >
             Limpar Todo Banco de Produção
           </button>
        </div>
      )}
      <ModalForm />
    </Layout>
  );
};

