        <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-blue-600/10 rounded-full blur-[120px]"></div>
        <div className="absolute bottom-[-20%] right-[-20%] w-[60%] h-[60%] bg-indigo-600/10 rounded-full blur-[120px]"></div>

        <div className="bg-[#111827]/80 backdrop-blur-xl p-12 rounded-[3rem] shadow-2xl w-full max-w-md border border-gray-800 text-center animate-in zoom-in-95 duration-700 relative z-10">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl mx-auto mb-8 flex items-center justify-center shadow-2xl shadow-blue-500/20 transform -rotate-6">
            <i className="fas fa-shield-alt text-4xl text-white"></i>
          </div>
          <h1 className="text-4xl font-black mb-1 uppercase tracking-tighter text-white font-mono">VM SEGUROS</h1>
          <p className="text-gray-500 text-[11px] mb-10 uppercase font-black tracking-[0.3em]">Cloud Infrastructure</p>

          <div className="space-y-4">
            <div className="relative">
              <i className="fas fa-user absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 text-sm"></i>
              <input 
                type="text" 
                placeholder="Identificação" 
                className="w-full p-5 pl-12 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold transition uppercase outline-none focus:border-blue-500"
                value={loginForm.username}
                onChange={(e) => setLoginForm({ ...loginForm, username: e.target.value })}
              />
            </div>
            <div className="relative">
              <i className="fas fa-lock absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 text-sm"></i>
              <input 
                type="password" 
                placeholder="Senha de Acesso" 
                className="w-full p-5 pl-12 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold transition outline-none focus:border-blue-500"
                value={loginForm.password}
                onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}
                onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
              />
            </div>
            <button 
              onClick={handleLogin}
              className="w-full bg-blue-600 hover:bg-blue-500 p-5 rounded-2xl font-black uppercase transition-all shadow-xl shadow-blue-600/20 text-white active:scale-95"
            >
              Autenticar
            </button>
          </div>
          <p className="mt-8 text-[9px] text-gray-600 uppercase font-bold tracking-widest">Acesso Restrito • 2024</p>
        </div>
      </div>
    );
  }

  // Implementation of Modal and other views remains but with layout/container consistency
  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1600px] mx-auto h-full">
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'comissao' && <div className="text-white">Financeiro Content (Refined)</div>}
        {activeSection === 'cadastrar-indicacao' && <div className="text-white">Distribuir Leads Content</div>}
        {/* Adicione outras condicionais aqui */}
      </div>

      {aiLead && <AiAssistant lead={aiLead} onClose={() => setAiLead(null)} />}

      {/* O ModalForm original pode ser mantido aqui para edição de cards */}
    </Layout>
  );
};

export default App;

