import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';
import AiAssistant from './components/AiAssistant';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);

  // Selection state
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
  const [selectedIndicacoes, setSelectedIndicacoes] = useState<string[]>([]);

  // Modals / AI
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [aiLead, setAiLead] = useState<any>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => u.login === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  const filteredVendas = useMemo(() => {
    let list = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(v => v.cliente.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [vendas, user, searchTerm]);

  const filteredIndicacoes = useMemo(() => {
    let list = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(i => i.cliente.toLowerCase().includes(searchTerm.toLowerCase()) || i.veiculo.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [indicacoes, user, searchTerm]);

  const handleBulkDelete = async (type: 'vendas' | 'indicacoes') => {
    if (confirm("Deseja realmente excluir os itens selecionados?")) {
      const targets = type === 'vendas' ? selectedVendas : selectedIndicacoes;
      for (const id of targets) await cloud.apagar(type, id);
      type === 'vendas' ? setSelectedVendas([]) : setSelectedIndicacoes([]);
    }
  };

  // --- Views ---

  const SearchBar = () => (
    <div className="relative mb-6">
      <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-500"></i>
      <input 
        type="text" 
        placeholder="Pesquisar..." 
        className="w-full bg-[#111827] border border-gray-800 rounded-2xl py-3 pl-12 pr-4 text-xs font-bold text-white outline-none focus:border-blue-500 transition-all uppercase"
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />
    </div>
  );

  const Dashboard = () => {
    const today = new Date().setHours(0, 0, 0, 0);
    const vHoje = filteredVendas.filter(v => v.dataCriacao >= today);
    const comissaoHoje = vHoje.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);
    const targets = user?.isAdmin ? usuarios : [user!];

    return (
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
        <h2 className="text-3xl font-black uppercase text-white mb-8 tracking-tighter">Cockpit</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          <div className="bg-[#111827] p-8 rounded-3xl border border-blue-900/30">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-1">Vendas Hoje</p>
            <h2 className="text-5xl font-black text-white">{vHoje.length}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-3xl border border-green-900/30">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-1">Comissão Hoje</p>
            <h2 className="text-5xl font-black text-green-500">{FORMAT_BRL(comissaoHoje)}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-3xl border border-gray-800">
            <p className="text-gray-500 text-[10px] font-bold uppercase mb-1">Total Leads</p>
            <h2 className="text-5xl font-black text-white">{filteredIndicacoes.length}</h2>
          </div>
        </div>

        <h2 className="text-xl font-black uppercase mb-8 text-white tracking-tighter border-l-4 border-blue-600 pl-4">Metas de Performance</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {targets.map(u => {
            const meta = metas.find(m => m.vendedor === u.nome) || { meta_salario: 1, meta_premio: 1 };
            const userVendas = vendas.filter(v => v.vendedor === u.nome && v.status === 'Pagamento Efetuado');
            const realC = userVendas.reduce((a, b) => a + Number(b.comissao_vendedor || 0), 0);
            const pC = Math.min((realC / (meta.meta_salario || 1)) * 100, 100);

            return (
              <div key={u.id} className="bg-[#111827] p-6 rounded-3xl border border-gray-800">
                <h4 className="text-[11px] font-black uppercase text-blue-400 mb-4">{u.nome}</h4>
                <div className="flex justify-between text-[10px] text-gray-400 mb-2 font-bold uppercase">
                  <span>Alcance: {FORMAT_BRL(realC)}</span>
                  <span>{pC.toFixed(0)}%</span>
                </div>
                <div className="bg-[#1e293b] rounded-full h-2 w-full overflow-hidden">
                  <div className="bg-gradient-to-r from-blue-600 to-blue-400 h-full transition-all duration-1000" style={{ width: `${pC}%` }}></div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const KanbanIndicacoes = () => (
    <div className="animate-in fade-in duration-300 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-black uppercase text-yellow-500 tracking-tighter">Fluxo de Leads</h2>
        <button onClick={() => { setModalType('indicacao'); setEditingItem(null); }} className="bg-yellow-500 px-6 py-2 rounded-xl font-black text-[11px] uppercase text-black">Novo Lead</button>
      </div>
      <SearchBar />
      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {INDICACAO_STATUS_MAP.map(status => (
          <div key={status} className="kanban-column bg-[#0f172a] rounded-[2rem] p-4 border border-gray-800 flex flex-col">
            <h3 className="text-[10px] font-black uppercase text-gray-500 mb-6 text-center">{status}</h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
              {filteredIndicacoes.filter(i => i.status === status).map(i => (
                <div key={i.id} onClick={() => { setModalType('indicacao'); setEditingItem(i); }} className="bg-[#111827] border border-gray-800 p-5 rounded-3xl border-l-4 border-l-yellow-500 hover:scale-[1.02] transition-all cursor-pointer">
                  <h4 className="text-[11px] font-black uppercase text-white">{i.cliente}</h4>
                  <p className="text-[10px] text-gray-400 mt-1 uppercase">{i.veiculo}</p>
                  <p className="text-[11px] text-blue-500 mt-3 font-black">{i.tel}</p>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const KanbanVendas = () => (
    <div className="animate-in fade-in duration-300 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-black uppercase text-blue-500 tracking-tighter">Produção</h2>
        <button onClick={() => { setModalType('venda'); setEditingItem(null); }} className="bg-blue-600 px-6 py-2 rounded-xl font-black text-[11px] uppercase text-white">Lançar Venda</button>
      </div>
      <SearchBar />
      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {VENDA_STATUS_MAP.map(status => (
          <div key={status} className="kanban-column bg-[#0f172a] rounded-[2rem] p-4 border border-gray-800 flex flex-col">
            <h3 className="text-[10px] font-black uppercase text-gray-500 mb-6 text-center">{status}</h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
              {filteredVendas.filter(v => v.status === status).map(v => (
                <div key={v.id} onClick={() => { setModalType('venda'); setEditingItem(v); }} className="bg-[#111827] border border-gray-800 p-5 rounded-3xl border-l-4 border-l-blue-600 hover:scale-[1.02] transition-all cursor-pointer">
                  <h4 className="text-[11px] font-black uppercase text-white mb-2">{v.cliente}</h4>
                  <div className="bg-[#0f172a] p-2 rounded-xl border border-gray-800 text-center">
                    <p className="text-[12px] font-black text-white">{FORMAT_BRL(v.valor)}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const Financeiro = () => {
    const concluido = filteredVendas.filter(v => v.status === 'Pagamento Efetuado');
    const totalComissao = concluido.reduce((a, b) => a + Number(user?.isAdmin ? b.comissao_cheia : b.comissao_vendedor), 0);
    return (
      <div className="animate-in fade-in duration-500">
        <h2 className="text-3xl font-black uppercase text-green-500 mb-8 tracking-tighter">Financeiro</h2>
        <div className="bg-[#111827] p-10 rounded-[2.5rem] border border-green-900/30 text-center mb-8">
          <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">Comissão Realizada</p>
          <h2 className="text-6xl font-black text-green-500 tracking-tighter">{FORMAT_BRL(totalComissao)}</h2>
        </div>
        <div className="bg-[#111827] rounded-3xl border border-gray-800 overflow-hidden">
          <table className="w-full text-left text-xs">
            <thead className="bg-gray-800 text-gray-400 uppercase">
              <tr>
                <th className="p-5">Cliente</th>
                <th className="p-5">Prêmio</th>
                <th className="p-5">Minha Parte</th>
              </tr>
            </thead>
            <tbody>
              {concluido.map(v => (
                <tr key={v.id} className="border-b border-gray-800">
                  <td className="p-5 font-bold uppercase">{v.cliente}</td>
                  <td className="p-5">{FORMAT_BRL(v.valor)}</td>
                  <td className="p-5 font-black text-green-500">{FORMAT_BRL(user?.isAdmin ? v.comissao_cheia : v.comissao_vendedor)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  const DistribuirLeads = () => {
    const [f, setF] = useState({ cliente: '', tel: '', veiculo: '', vendedor: '', suhai: false, info: '' });
    const send = async (e: React.FormEvent) => {
      e.preventDefault();
      await cloud.salvarIndicacao({ ...f, status: 'NOVA INDICAÇÃO', dataCriacao: Date.now() });
      alert('Lead distribuído!');
      setF({ cliente: '', tel: '', veiculo: '', vendedor: '', suhai: false, info: '' });
    };
    return (
      <div className="max-w-xl mx-auto animate-in slide-in-from-top-4 duration-500">
        <div className="bg-[#111827] p-10 rounded-[2.5rem] border border-gray-800 shadow-2xl">
          <h2 className="text-xl font-black uppercase text-yellow-500 mb-8 text-center tracking-tighter">Distribuir Lead</h2>
          <form onSubmit={send} className="space-y-4">
            <input value={f.cliente} onChange={e => setF({...f, cliente: e.target.value})} placeholder="CLIENTE" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white uppercase outline-none focus:border-blue-500" required />
            <input value={f.tel} onChange={e => setF({...f, tel: e.target.value})} placeholder="WHATSAPP" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none focus:border-blue-500" required />
            <input value={f.veiculo} onChange={e => setF({...f, veiculo: e.target.value})} placeholder="VEÍCULO" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white uppercase outline-none focus:border-blue-500" required />
            <select value={f.vendedor} onChange={e => setF({...f, vendedor: e.target.value})} className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white uppercase outline-none" required>
