            </select>
            <div className="flex items-center gap-3 p-4 bg-[#0f172a] border border-gray-800 rounded-2xl">
              <input type="checkbox" checked={f.suhai} onChange={e => setF({...f, suhai: e.target.checked})} className="w-5 h-5 accent-green-500" />
              <label className="text-[10px] font-black uppercase text-green-500">Lead Suhai Especial</label>
            </div>
            <button type="submit" className="w-full bg-yellow-500 p-5 rounded-2xl font-black uppercase text-black transition hover:scale-[1.02]">Enviar Lead</button>
          </form>
        </div>
      </div>
    );
  };

  const VendedoresView = () => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-3xl font-black uppercase text-red-500 tracking-tighter">Equipe Comercial</h2>
        <button onClick={() => { setModalType('usuario'); setEditingItem(null); }} className="bg-red-600 px-6 py-2 rounded-xl font-black text-[11px] uppercase text-white">Novo Vendedor</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {usuarios.map(u => (
          <div key={u.id} onClick={() => { setModalType('usuario'); setEditingItem(u); }} className="bg-[#111827] p-8 rounded-3xl border border-gray-800 border-l-4 border-l-red-600 hover:scale-[1.02] transition-all cursor-pointer shadow-xl">
