            <div className="flex justify-between items-center">
              <span className="text-[10px] text-gray-500 uppercase font-bold">Setor: {u.setor}</span>
              <span className="text-[10px] text-red-400 uppercase font-bold">{u.comissao}%</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const MetasView = () => {
    const [sel, setSel] = useState('');
    const [mf, setMf] = useState({ salario: 0, premio: 0, qtd: 0 });
    const save = async () => {
       await cloud.salvarMeta({ vendedor: sel, meta_salario: mf.salario, meta_premio: mf.premio, meta_qtd: mf.qtd });
       alert('Meta atualizada!');
    };
    return (
      <div className="max-w-2xl mx-auto animate-in fade-in duration-500">
        <h2 className="text-3xl font-black uppercase text-blue-400 mb-8 tracking-tighter text-center">Gestão de Objetivos</h2>
        <div className="bg-[#111827] p-10 rounded-[2.5rem] border border-gray-800 shadow-2xl space-y-6">
          <select value={sel} onChange={e => setSel(e.target.value)} className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none">
            <option value="">Selecione o Vendedor...</option>
            {usuarios.map(u => <option key={u.id} value={u.nome}>{u.nome}</option>)}
          </select>
          <div className="grid grid-cols-2 gap-4">
            <input type="number" placeholder="META RENDA (R$)" onChange={e => setMf({...mf, salario: Number(e.target.value)})} className="p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none" />
            <input type="number" placeholder="META PRÊMIO (R$)" onChange={e => setMf({...mf, premio: Number(e.target.value)})} className="p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none" />
          </div>
          <button onClick={save} className="w-full bg-blue-600 p-5 rounded-2xl font-black uppercase text-white shadow-lg">Definir Metas</button>
        </div>
      </div>
    );
