  const LeadSuhaiView = () => {
    const sV = filteredVendas.filter(v => v.suhai && v.status === 'Pagamento Efetuado');
    const totalS = sV.reduce((a, b) => a + Number(b.comissao_cheia), 0);
    return (
      <div className="animate-in fade-in duration-500">
        <h2 className="text-3xl font-black uppercase text-green-400 mb-8 tracking-tighter">Produção Suhai</h2>
        <div className="bg-[#111827] p-10 rounded-[2.5rem] border border-green-500/20 text-center mb-8">
          <p className="text-gray-500 text-[10px] font-bold uppercase mb-2">Comissão Empresa Suhai</p>
          <h2 className="text-6xl font-black text-green-400 tracking-tighter">{FORMAT_BRL(totalS)}</h2>
        </div>
        <div className="bg-[#111827] rounded-3xl border border-gray-800 overflow-hidden">
          <table className="w-full text-left text-xs">
            <thead className="bg-gray-800 text-gray-400 uppercase">
              <tr>
                <th className="p-5">Cliente</th>
                <th className="p-5">Vendedor</th>
                <th className="p-5">Prêmio</th>
              </tr>
            </thead>
            <tbody>
              {sV.map(v => (
                <tr key={v.id} className="border-b border-gray-800">
                  <td className="p-5 font-bold uppercase">{v.cliente}</td>
                  <td className="p-5 uppercase text-gray-400">{v.vendedor}</td>
                  <td className="p-5 font-black">{FORMAT_BRL(v.valor)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  const ModalForm = () => {
    const [vf, setVf] = useState<any>(editingItem || {});
    if (!modalType) return null;
    const save = async (e: React.FormEvent) => {
      e.preventDefault();
      if (modalType === 'venda') await cloud.salvarVenda({ ...vf, dataCriacao: vf.dataCriacao || Date.now() });
      if (modalType === 'indicacao') await cloud.salvarIndicacao({ ...vf, dataCriacao: vf.dataCriacao || Date.now() });
      if (modalType === 'usuario') await cloud.salvarUsuario({ ...vf });
      setModalType(null);
    };
    return (
      <div className="fixed inset-0 bg-black/90 backdrop-blur-md flex items-center justify-center z-[400] p-4">
        <div className="bg-[#111827] p-10 rounded-[3rem] w-full max-w-md border border-gray-800 shadow-2xl">
          <h3 className="text-xl font-black uppercase text-white mb-8">Gestão de {modalType}</h3>
          <form onSubmit={save} className="space-y-4">
            <input value={vf.cliente || vf.nome || ''} onChange={e => setVf({...vf, [modalType === 'usuario' ? 'nome' : 'cliente']: e.target.value})} placeholder="NOME" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none uppercase" required />
            {modalType !== 'usuario' && <input value={vf.tel || ''} onChange={e => setVf({...vf, tel: e.target.value})} placeholder="TELEFONE" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none" required />}
            {modalType === 'venda' && (
              <div className="space-y-4">
                <input type="number" value={vf.valor || ''} onChange={e => setVf({...vf, valor: Number(e.target.value)})} placeholder="PRÊMIO (R$)" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none" required />
                <select value={vf.status || 'Fazer Vistoria'} onChange={e => setVf({...vf, status: e.target.value})} className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-white outline-none">
                   {VENDA_STATUS_MAP.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            )}
            <div className="flex gap-4 pt-6">
              <button type="button" onClick={() => setModalType(null)} className="flex-1 bg-gray-800 p-4 rounded-2xl font-black uppercase text-white">Cancelar</button>
              <button type="submit" className="flex-1 bg-blue-600 p-4 rounded-2xl font-black uppercase text-white">Salvar</button>
            </div>
          </form>
        </div>
      </div>
    );
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0b0f1a] relative overflow-hidden">
        <div className="bg-[#111827]/80 backdrop-blur-xl p-12 rounded-[3rem] shadow-2xl w-full max-w-md border border-gray-800 text-center animate-in zoom-in-95 duration-700 z-10">
          <i className="fas fa-shield-alt text-6xl text-blue-600 mb-8"></i>
          <h1 className="text-4xl font-black mb-1 text-white tracking-tighter">VM SEGUROS</h1>
          <p className="text-gray-500 text-[10px] mb-10 uppercase font-black tracking-[0.3em]">Cloud Security</p>
          <div className="space-y-4">
            <input type="text" placeholder="LOGIN" className="w-full p-5 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold uppercase outline-none focus:border-blue-500" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} />
            <input type="password" placeholder="SENHA" className="w-full p-5 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold outline-none focus:border-blue-500" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} onKeyDown={e => e.key === 'Enter' && handleLogin()} />
            <button onClick={handleLogin} className="w-full bg-blue-600 p-5 rounded-2xl font-black uppercase text-white shadow-xl shadow-blue-600/20 active:scale-95 transition-all">Autenticar</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1400px] mx-auto h-full p-4">
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'comissao' && <Financeiro />}
        {activeSection === 'cadastrar-indicacao' && <DistribuirLeads />}
        {activeSection === 'vendedores' && <VendedoresView />}
        {activeSection === 'metas' && <MetasView />}
        {activeSection === 'lead-suhai-page' && <LeadSuhaiView />}
        {activeSection === 'configuracoes' && (
           <div className="p-10 bg-[#111827] rounded-[2.5rem] border border-gray-800 text-center">
             <h2 className="text-2xl font-black uppercase text-red-500 mb-8 tracking-tighter">Manutenção Estrutural</h2>
             <button onClick={async () => { if(confirm("Deseja resetar o banco de produção?")) { for(let v of vendas) await cloud.apagar('vendas', v.id!); } }} className="bg-red-600/10 text-red-500 border border-red-600 p-5 rounded-2xl font-black uppercase transition-all hover:bg-red-600 hover:text-white">Resetar Banco de Dados</button>
           </div>
        )}
      </div>
      {aiLead && <AiAssistant lead={aiLead} onClose={() => setAiLead(null)} />}
      <ModalForm />
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';
import AiAssistant from './components/AiAssistant';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);

  // Selection state
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
  const [selectedIndicacoes, setSelectedIndicacoes] = useState<string[]>([]);

  // Modals / AI
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [aiLead, setAiLead] = useState<any>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => u.login === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  const filteredVendas = useMemo(() => {
    let list = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(v => v.cliente.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [vendas, user, searchTerm]);

  const filteredIndicacoes = useMemo(() => {
    let list = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(i => i.cliente.toLowerCase().includes(searchTerm.toLowerCase()) || i.veiculo.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [indicacoes, user, searchTerm]);

  const handleBulkDelete = async (type: 'vendas' | 'indicacoes') => {
    if (confirm("Deseja realmente excluir os itens selecionados?")) {
      const targets = type === 'vendas' ? selectedVendas : selectedIndicacoes;
      for (const id of targets) await cloud.apagar(type, id);
      type === 'vendas' ? setSelectedVendas([]) : setSelectedIndicacoes([]);
    }
  };

  // --- Search UI ---
  const SearchBar = () => (
    <div className="relative mb-6">
      <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-500"></i>
      <input 
        type="text" 
        placeholder="Localizar cliente ou registro..." 
        className="w-full bg-[#111827] border border-gray-800 rounded-2xl py-4 pl-12 pr-4 text-xs font-bold text-white outline-none focus:border-blue-500 transition-all uppercase"
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />
    </div>
  );

  // --- Views ---

  const Dashboard = () => {
    const today = new Date().setHours(0, 0, 0, 0);
    const vHoje = filteredVendas.filter(v => v.dataCriacao >= today);
    const comissaoHoje = vHoje.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);
    const targets = user?.isAdmin ? usuarios : [user!];

    return (
      <div className="animate-in fade-in duration-500">
