      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {VENDA_STATUS_MAP.map(status => (
          <div key={status} className="kanban-column bg-[#0f172a] rounded-[2.5rem] p-5 border border-gray-800 flex flex-col">
