          <p className="text-gray-500 text-[11px] font-black uppercase mb-2 tracking-[0.3em]">Total Realizado</p>
          <h2 className="text-7xl font-black text-green-500 tracking-tighter">{FORMAT_BRL(totalComissao)}</h2>
