            {modalType === 'venda' && (
              <div className="space-y-5">
                <label className="text-[10px] font-black text-gray-600 uppercase ml-2">Financeiro da Apólice</label>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   <input type="number" step="0.01" value={vf.valor || ''} onChange={e => setVf({...vf, valor: Number(e.target.value)})} placeholder="VALOR DO PRÊMIO (R$)" className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-mono outline-none" required />
                   <input type="number" step="0.01" value={vf.comissao_cheia || ''} onChange={e => setVf({...vf, comissao_cheia: Number(e.target.value)})} placeholder="COMISSÃO CHEIA (R$)" className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-mono outline-none" required />
                   <input type="number" step="0.01" value={vf.comissao_vendedor || ''} onChange={e => setVf({...vf, comissao_vendedor: Number(e.target.value)})} placeholder="COMISSÃO VENDEDOR (R$)" className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-mono outline-none" required />
                   <select value={vf.status || 'Fazer Vistoria'} onChange={e => setVf({...vf, status: e.target.value})} className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold uppercase outline-none">
                      {VENDA_STATUS_MAP.map(s => <option key={s} value={s}>{s}</option>)}
                   </select>
                </div>

                <div className="flex items-center gap-4 p-5 bg-[#0f172a] border border-gray-800 rounded-2xl">
                  <input type="checkbox" checked={vf.suhai || false} onChange={e => setVf({...vf, suhai: e.target.checked})} className="w-6 h-6 accent-green-500" id="m-suhai" />
                  <label htmlFor="m-suhai" className="text-[10px] font-black uppercase text-green-500">Parceiro Suhai</label>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-600 uppercase ml-2">Responsável pela Venda</label>
                  <select 
                    value={vf.vendedor || ''} 
                    onChange={e => setVf({...vf, vendedor: e.target.value})} 
                    disabled={!user?.isAdmin}
                    className={`w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold uppercase outline-none ${!user?.isAdmin ? 'opacity-50 cursor-not-allowed border-blue-900/50' : 'focus:border-blue-500'}`}
                    required
                  >
                    <option value="">Selecione o Vendedor...</option>
                    {usuarios.map(u => <option key={u.id} value={u.nome}>{u.nome}</option>)}
                    {user?.isAdmin && !usuarios.find(u => u.nome === user.nome) && <option value={user.nome}>{user.nome}</option>}
                  </select>
                  {!user?.isAdmin && <p className="text-[8px] text-gray-500 uppercase ml-2 italic">* Apenas administradores podem alterar o vendedor responsável.</p>}
                </div>
              </div>
            )}

            {modalType === 'usuario' && (
              <div className="space-y-4">
                 <input value={vf.login || ''} onChange={e => setVf({...vf, login: e.target.value})} placeholder="LOGIN DE ACESSO" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" required />
                 <input type="password" value={vf.senha || ''} onChange={e => setVf({...vf, senha: e.target.value})} placeholder="SENHA" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" required />
                 <div className="grid grid-cols-2 gap-4">
                    <select value={vf.setor || 'VENDEDOR'} onChange={e => setVf({...vf, setor: e.target.value})} className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold uppercase outline-none">
                      <option value="VENDEDOR">VENDEDOR</option>
                      <option value="ADMIN">ADMIN</option>
                    </select>
                    <input type="number" value={vf.comissao || ''} onChange={e => setVf({...vf, comissao: Number(e.target.value)})} placeholder="% COMISSÃO" className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
                 </div>
              </div>
            )}

            <div className="flex gap-4 pt-8">
              <button type="button" onClick={() => setModalType(null)} className="flex-1 bg-gray-800 p-6 rounded-[2rem] font-black uppercase text-white hover:bg-gray-700 transition-all">Sair</button>
              <button type="submit" className="flex-1 bg-blue-600 p-6 rounded-[2rem] font-black uppercase text-white shadow-xl shadow-blue-600/20 hover:scale-105 transition-all">Confirmar</button>
            </div>
          </form>
        </div>
      </div>
    );
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0b0f1a] relative overflow-hidden">
        <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-blue-600/10 rounded-full blur-[120px]"></div>
        <div className="bg-[#111827]/80 backdrop-blur-xl p-12 rounded-[3.5rem] shadow-2xl w-full max-w-md border border-gray-800 text-center animate-in zoom-in-95 duration-700 relative z-10">
          <div className="w-24 h-24 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-[2rem] mx-auto mb-10 flex items-center justify-center shadow-2xl shadow-blue-500/30 transform rotate-6 hover:rotate-0 transition-transform duration-500">
            <i className="fas fa-shield-alt text-5xl text-white"></i>
          </div>
          <h1 className="text-4xl font-black mb-1 uppercase tracking-tighter text-white font-mono">VM SEGUROS</h1>
          <p className="text-gray-500 text-[10px] mb-12 uppercase font-black tracking-[0.4em]">Elite Cloud CRM</p>
          <div className="space-y-5">
            <input type="text" placeholder="LOGIN IDENTIFICAÇÃO" className="w-full p-6 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold transition uppercase outline-none focus:border-blue-500" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} />
            <input type="password" placeholder="CHAVE DE ACESSO" className="w-full p-6 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold transition outline-none focus:border-blue-500" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} onKeyDown={e => e.key === 'Enter' && handleLogin()} />
            <button onClick={handleLogin} className="w-full bg-blue-600 hover:bg-blue-500 p-6 rounded-[2rem] font-black uppercase transition-all shadow-2xl shadow-blue-600/30 text-white mt-4 active:scale-95">Autenticar Sistema</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1600px] mx-auto h-full p-2">
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'comissao' && <Financeiro />}
        {activeSection === 'cadastrar-indicacao' && <DistribuirLeads />}
        {activeSection === 'vendedores' && <VendedoresView />}
        {activeSection === 'metas' && <MetasView />}
        {activeSection === 'lead-suhai-page' && <LeadSuhaiView />}
        {activeSection === 'configuracoes' && (
           <div className="max-w-xl mx-auto p-12 bg-[#111827] rounded-[3rem] border border-gray-800 text-center shadow-2xl animate-in fade-in duration-500">
             <i className="fas fa-cogs text-6xl text-red-600 mb-8"></i>
             <h2 className="text-3xl font-black uppercase text-white mb-4 tracking-tighter">Manutenção de Banco</h2>
             <p className="text-gray-500 text-sm mb-10 font-bold uppercase">Área restrita para reset estrutural de dados.</p>
             <button onClick={async () => { if(confirm("Deseja resetar o banco de produção? Esta ação é irreversível.")) { for(let v of vendas) await cloud.apagar('vendas', v.id!); alert("Banco resetado."); } }} className="w-full bg-red-600/10 text-red-500 border-2 border-red-600 p-6 rounded-[2rem] font-black uppercase transition-all hover:bg-red-600 hover:text-white">Executar Factory Reset</button>
           </div>
        )}
      </div>
      {aiLead && <AiAssistant lead={aiLead} onClose={() => setAiLead(null)} />}
      <ModalForm />
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';
import AiAssistant from './components/AiAssistant';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);

  // Modals / AI
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [aiLead, setAiLead] = useState<any>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => u.login === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  const filteredVendas = useMemo(() => {
    let list = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(v => v.cliente.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [vendas, user, searchTerm]);

  const filteredIndicacoes = useMemo(() => {
    let list = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(i => i.cliente.toLowerCase().includes(searchTerm.toLowerCase()) || i.veiculo.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [indicacoes, user, searchTerm]);

  // --- Search UI ---
  const SearchBar = () => (
    <div className="relative mb-6">
      <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-500"></i>
      <input 
        type="text" 
        placeholder="Localizar cliente ou registro..." 
        className="w-full bg-[#111827] border border-gray-800 rounded-2xl py-4 pl-12 pr-4 text-xs font-bold text-white outline-none focus:border-blue-500 transition-all uppercase"
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />
    </div>
  );

  // --- Views ---

  const Dashboard = () => {
    const today = new Date().setHours(0, 0, 0, 0);
    const vHoje = filteredVendas.filter(v => v.dataCriacao >= today);
    const comissaoHoje = vHoje.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);
    const targets = user?.isAdmin ? usuarios : [user!];

    return (
      <div className="animate-in fade-in duration-500">
        <div className="flex justify-between items-end mb-10">
          <div>
            <h2 className="text-4xl font-black uppercase text-white tracking-tighter">Cockpit</h2>
            <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Performance Operacional</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
          <div className="bg-[#111827] p-8 rounded-[2rem] border border-blue-900/30 shadow-2xl relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 text-6xl text-blue-500/5 group-hover:rotate-12 transition-transform"><i className="fas fa-shopping-bag"></i></div>
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Vendas (Hoje)</p>
            <h2 className="text-6xl font-black text-white">{vHoje.length}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2rem] border border-green-900/30 shadow-2xl relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 text-6xl text-green-500/5 group-hover:rotate-12 transition-transform"><i className="fas fa-dollar-sign"></i></div>
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Comissão (Hoje)</p>
            <h2 className="text-6xl font-black text-green-500">{FORMAT_BRL(comissaoHoje)}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2rem] border border-gray-800 shadow-2xl relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 text-6xl text-white/5 group-hover:rotate-12 transition-transform"><i className="fas fa-users"></i></div>
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Leads Ativos</p>
            <h2 className="text-6xl font-black text-white">{filteredIndicacoes.length}</h2>
          </div>
        </div>

        <h2 className="text-xl font-black uppercase mb-8 text-white tracking-tighter border-l-4 border-blue-600 pl-4">Metas do Vendedor</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {targets.map(u => {
            const meta = metas.find(m => m.vendedor === u.nome) || { meta_salario: 1, meta_premio: 1 };
            const userVendas = vendas.filter(v => v.vendedor === u.nome && v.status === 'Pagamento Efetuado');
            const realC = userVendas.reduce((a, b) => a + Number(b.comissao_vendedor || 0), 0);
            const pC = Math.min((realC / (meta.meta_salario || 1)) * 100, 100);

            return (
              <div key={u.id} className="bg-[#111827] p-8 rounded-3xl border border-gray-800 hover:border-blue-500/30 transition-all">
                <div className="flex justify-between items-center mb-6">
                  <h4 className="text-[12px] font-black uppercase text-blue-400">{u.nome}</h4>
                  <span className="text-[10px] font-bold text-gray-600">{pC.toFixed(0)}%</span>
                </div>
                <div className="bg-[#1e293b] rounded-full h-3 w-full overflow-hidden shadow-inner">
                  <div className="bg-gradient-to-r from-blue-600 to-blue-400 h-full transition-all duration-1000" style={{ width: `${pC}%` }}></div>
                </div>
                <div className="mt-4 flex justify-between text-[9px] font-black uppercase text-gray-500">
                  <span>Atual: {FORMAT_BRL(realC)}</span>
                  <span>Meta: {FORMAT_BRL(meta.meta_salario)}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const KanbanIndicacoes = () => (
    <div className="animate-in fade-in duration-300 h-full flex flex-col">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-black uppercase text-yellow-500 tracking-tighter">Leads</h2>
          <p className="text-[10px] font-bold text-gray-500 uppercase">Gestão de novas indicações</p>
        </div>
        <button onClick={() => { setModalType('indicacao'); setEditingItem(null); }} className="bg-yellow-500 hover:bg-yellow-400 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-black transition-all shadow-lg shadow-yellow-500/20">Novo Lead</button>
      </div>
      <SearchBar />
      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {INDICACAO_STATUS_MAP.map(status => (
          <div key={status} className="kanban-column bg-[#0f172a] rounded-[2.5rem] p-5 border border-gray-800 flex flex-col">
            <h3 className="text-[10px] font-black uppercase text-gray-500 mb-6 text-center tracking-[0.2em]">{status}</h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
              {filteredIndicacoes.filter(i => i.status === status).map(i => (
                <div key={i.id} onClick={() => { setModalType('indicacao'); setEditingItem(i); }} className="group bg-[#111827] border border-gray-800 p-6 rounded-[2rem] border-l-4 border-l-yellow-500 hover:scale-[1.02] transition-all cursor-pointer shadow-xl relative">
                   <div className="absolute top-4 right-4 text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity cursor-help" onClick={(e) => { e.stopPropagation(); setAiLead(i); }}><i className="fas fa-robot"></i></div>
                  <h4 className="text-[12px] font-black uppercase text-white mb-1">{i.cliente}</h4>
                  <p className="text-[10px] text-gray-500 font-bold uppercase mb-4">{i.veiculo}</p>
                  <div className="flex justify-between items-center">
                    <span className="text-[11px] text-blue-400 font-black"><i className="fab fa-whatsapp mr-1 text-green-500"></i> {i.tel}</span>
                    {i.suhai && <span className="s-suhai-pulse text-[12px]">S</span>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const KanbanVendas = () => (
    <div className="animate-in fade-in duration-300 h-full flex flex-col">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-black uppercase text-blue-500 tracking-tighter">Produção</h2>
          <p className="text-[10px] font-bold text-gray-500 uppercase">Acompanhamento de apólices</p>
        </div>
        <button onClick={() => { setModalType('venda'); setEditingItem(null); }} className="bg-blue-600 hover:bg-blue-500 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-white transition-all shadow-lg shadow-blue-500/20">Lançar Venda</button>
      </div>
      <SearchBar />
      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {VENDA_STATUS_MAP.map(status => (
          <div key={status} className="kanban-column bg-[#0f172a] rounded-[2.5rem] p-5 border border-gray-800 flex flex-col">
            <h3 className="text-[10px] font-black uppercase text-gray-500 mb-6 text-center tracking-[0.2em]">{status}</h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
              {filteredVendas.filter(v => v.status === status).map(v => (
                <div key={v.id} onClick={() => { setModalType('venda'); setEditingItem(v); }} className="bg-[#111827] border border-gray-800 p-6 rounded-[2rem] border-l-4 border-l-blue-600 hover:scale-[1.02] transition-all cursor-pointer shadow-xl">
                  <div className="flex justify-between items-start mb-1">
                    <h4 className="text-[12px] font-black uppercase text-white leading-tight pr-4">{v.cliente}</h4>
                    {v.suhai && <i className="fas fa-star text-green-500 text-[10px]"></i>}
                  </div>
                  <p className="text-[10px] text-blue-500 font-black mb-4"><i className="fab fa-whatsapp mr-1"></i>{v.tel}</p>

                  <div className="bg-[#0f172a] p-4 rounded-2xl mb-4 border border-gray-800 text-center shadow-inner">
                    <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Prêmio Total</p>
                    <p className="text-[16px] font-black text-white">{FORMAT_BRL(v.valor)}</p>
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-[#0f172a] p-3 rounded-xl border border-gray-800 text-center">
                      <p className="text-[7px] font-black text-blue-500 uppercase mb-1">C. Cheia</p>
                      <p className="text-[11px] font-bold text-gray-400">{FORMAT_BRL(v.comissao_cheia)}</p>
                    </div>
                    <div className="bg-green-500/5 p-3 rounded-xl border border-green-500/20 text-center">
                      <p className="text-[7px] font-black text-green-500 uppercase mb-1">C. Vend.</p>
                      <p className="text-[11px] font-bold text-green-400">{FORMAT_BRL(v.comissao_vendedor)}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const Financeiro = () => {
    // FILTRO: Somente as vendas que estão em "Pagamento Efetuado" conforme solicitado
    const concluido = filteredVendas.filter(v => v.status === 'Pagamento Efetuado');
    // SOMA: Somar apenas o que estiver filtrado como concluído
    const totalComissao = concluido.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);

    return (
      <div className="animate-in fade-in duration-500">
        <h2 className="text-4xl font-black uppercase text-green-500 mb-10 tracking-tighter">Financeiro</h2>
        <div className="bg-[#111827] p-12 rounded-[3rem] border border-green-900/30 text-center mb-10 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-green-500"></div>
          <p className="text-gray-500 text-[11px] font-black uppercase mb-2 tracking-[0.3em]">Total Sua Parte (Vendas Pagas)</p>
          <h2 className="text-7xl font-black text-green-500 tracking-tighter">{FORMAT_BRL(totalComissao)}</h2>
        </div>
        <div className="bg-[#111827] rounded-[2rem] border border-gray-800 overflow-hidden shadow-xl">
          <table className="w-full text-left">
            <thead className="bg-[#1e293b] text-gray-400 text-[10px] uppercase font-black">
              <tr>
                <th className="p-6">Data</th>
                <th className="p-6">Cliente</th>
                <th className="p-6">Prêmio</th>
                <th className="p-6">Sua Parte / Vendedor</th>
              </tr>
            </thead>
            <tbody className="text-xs font-bold uppercase">
              {concluido.map(v => (
                <tr key={v.id} className="border-b border-gray-800 hover:bg-gray-800/20 transition-colors">
                  <td className="p-6 text-gray-500 font-mono">{new Date(v.dataCriacao).toLocaleDateString()}</td>
                  <td className="p-6 text-white">{v.cliente}</td>
                  <td className="p-6 text-gray-400">{FORMAT_BRL(v.valor)}</td>
                  <td className="p-6 font-black">
