          <p className="text-gray-500 text-[11px] font-black uppercase mb-2 tracking-[0.3em]">Receita Bruta Suhai</p>
          <h2 className="text-8xl font-black text-green-400 tracking-tighter">{FORMAT_BRL(totalS)}</h2>
