               <input value={vf.cliente || vf.nome || ''} onChange={e => setVf({...vf, [modalType === 'usuario' ? 'nome' : 'cliente']: e.target.value})} placeholder="NOME COMPLETO" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase focus:border-blue-500" required />
               {modalType !== 'usuario' && <input value={vf.tel || ''} onChange={e => setVf({...vf, tel: e.target.value})} placeholder="WHATSAPP / CELULAR" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" required />}
            </div>

            {modalType === 'venda' && (
              <div className="space-y-5">
                <label className="text-[10px] font-black text-gray-600 uppercase ml-2">Financeiro da Apólice</label>
