      setLoading(false);
    }
  };

  const handleSetupKey = async () => {
    try {
      await window.aistudio.openSelectKey();
      // Assume success and try again
      handleGenerate();
    } catch (e) {
      console.error("Erro ao abrir seletor de chave", e);
    }
