  return (
    <div className="fixed inset-y-0 right-0 w-full md:w-96 bg-[#111827]/95 backdrop-blur-xl border-l border-gray-800 z-[300] shadow-2xl p-6 flex flex-col animate-in slide-in-from-right duration-300">
