            <button onClick={handleLogin} className="w-full bg-blue-600 hover:bg-blue-500 p-6 rounded-[2rem] font-black uppercase transition-all shadow-2xl shadow-blue-600/30 text-white mt-4 active:scale-95">Autenticar Sistema</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1600px] mx-auto h-full p-2">
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'comissao' && <Financeiro />}
        {activeSection === 'cadastrar-indicacao' && <DistribuirLeads />}
        {activeSection === 'vendedores' && <VendedoresView />}
        {activeSection === 'metas' && <MetasView />}
        {activeSection === 'lead-suhai-page' && <LeadSuhaiView />}
        {activeSection === 'configuracoes' && <Configuracoes />}
      </div>
      {aiLead && <AiAssistant lead={aiLead} onClose={() => setAiLead(null)} />}
      <ModalForm />
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { gemini } from '../services/gemini';

interface AiAssistantProps {
  lead: { cliente: string; veiculo: string; info: string };
  onClose: () => void;
}

const AiAssistant: React.FC<AiAssistantProps> = ({ lead, onClose }) => {
  const [loading, setLoading] = useState(false);
  const [pitch, setPitch] = useState('');
  const [errorType, setErrorType] = useState<'NONE' | 'KEY_MISSING' | 'OTHER'>('NONE');

  const handleGenerate = async () => {
    setLoading(true);
    setErrorType('NONE');
    try {
      const res = await gemini.gerarPitchVenda(lead);
      setPitch(res || 'Não foi possível gerar o pitch no momento.');
    } catch (error: any) {
      console.error(error);
      // Handle missing key or invalid key errors by triggering the selection dialog
      if (error.message === 'API_KEY_MISSING' || (error.message && error.message.includes('Requested entity was not found'))) {
        setErrorType('KEY_MISSING');
      } else {
        setErrorType('OTHER');
        setPitch('Erro ao conectar com a inteligência artificial.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleSetupKey = async () => {
    try {
      // Fix: Trigger the selection dialog using casting to any for window.aistudio to bypass identical modifiers conflict in global Window interface
      await (window as any).aistudio.openSelectKey();
      // Per instructions, assume the key selection was successful and proceed
      handleGenerate();
    } catch (e) {
      console.error("Erro ao abrir seletor de chave", e);
    }
  };

  return (
    <div className="fixed inset-y-0 right-0 w-full md:w-96 bg-[#111827]/95 backdrop-blur-xl border-l border-gray-800 z-[300] shadow-2xl p-6 flex flex-col animate-in slide-in-from-right duration-300">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-lg font-black uppercase text-blue-400 flex items-center gap-2">
          <i className="fas fa-robot"></i> AI Sales Partner
        </h3>
        <button onClick={onClose} className="text-gray-400 hover:text-white transition">
          <i className="fas fa-times"></i>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto space-y-4 pr-2 scrollbar-thin">
        <div className="bg-[#1e293b] p-4 rounded-2xl border border-gray-700">
          <p className="text-[10px] uppercase font-bold text-gray-500 mb-1">Lead Selecionado</p>
          <p className="text-sm font-bold text-white uppercase">{lead.cliente}</p>
          <p className="text-[11px] text-blue-400">{lead.veiculo}</p>
        </div>

        {errorType === 'KEY_MISSING' && (
          <div className="bg-red-500/10 p-5 rounded-2xl border border-red-500/30 text-center">
            <i className="fas fa-key text-red-500 mb-3 text-2xl"></i>
            <p className="text-xs text-red-500 font-bold uppercase mb-4">Configuração Necessária</p>
            <p className="text-[10px] text-gray-400 mb-6 leading-tight uppercase">Para usar a IA no Netlify, você precisa selecionar uma chave de API válida.</p>
            <button 
              onClick={handleSetupKey}
              className="w-full bg-red-600 p-4 rounded-xl text-[10px] font-black uppercase text-white hover:bg-red-500 transition-all"
            >
              Configurar Chave de API
            </button>
            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[9px] text-gray-600 mt-4 block underline uppercase">Saiba mais sobre faturamento</a>
          </div>
        )}

        {pitch && errorType === 'NONE' ? (
          <div className="bg-blue-600/10 p-5 rounded-2xl border border-blue-500/30">
            <p className="text-[10px] uppercase font-bold text-blue-400 mb-3">Pitch Sugerido pela AI</p>
            <div className="text-sm text-gray-200 whitespace-pre-wrap leading-relaxed">
              {pitch}
            </div>
            <button 
              onClick={() => { navigator.clipboard.writeText(pitch); alert('Copiado!'); }}
              className="mt-4 w-full bg-blue-600 p-3 rounded-xl text-[10px] font-bold uppercase transition hover:bg-blue-500"
            >
              <i className="fas fa-copy mr-2"></i> Copiar para WhatsApp
            </button>
          </div>
        ) : errorType === 'NONE' && (
          <div className="text-center py-10">
            <i className="fas fa-magic text-4xl text-gray-700 mb-4"></i>
            <p className="text-xs text-gray-500 uppercase font-bold">A IA pode te ajudar a fechar este seguro.</p>
          </div>
        )}
      </div>

      <div className="pt-6 border-t border-gray-800">
        <button
          onClick={handleGenerate}
          disabled={loading || errorType === 'KEY_MISSING'}
          className={`w-full p-4 rounded-2xl font-black uppercase text-xs flex items-center justify-center gap-3 transition-all ${
            loading || errorType === 'KEY_MISSING' ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white hover:scale-105 active:scale-95'
          }`}
        >
          {loading ? (
            <>
              <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin"></div>
              Analisando...
            </>
          ) : (
            <>
              <i className="fas fa-bolt"></i> Gerar Estratégia
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default AiAssistant;

import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta, Empresa } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';
import AiAssistant from './components/AiAssistant';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);
  const [empresas, setEmpresas] = useState<Empresa[]>([]);

  // Selection State
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
  const [selectedIndicacoes, setSelectedIndicacoes] = useState<string[]>([]);

  // Modals / AI
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | 'empresa' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [aiLead, setAiLead] = useState<any>(null);

  // Drag and Drop State
  const [draggedItem, setDraggedItem] = useState<{ id: string, type: 'venda' | 'indicacao' } | null>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);
    const unsubEmpresas = cloud.subscribeEmpresas(setEmpresas);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
      unsubEmpresas();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => u.login === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  const filteredVendas = useMemo(() => {
    let list = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(v => v.cliente.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [vendas, user, searchTerm]);

  const filteredIndicacoes = useMemo(() => {
    let list = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
    if (searchTerm) {
      list = list.filter(i => i.cliente.toLowerCase().includes(searchTerm.toLowerCase()) || i.veiculo.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    return list;
  }, [indicacoes, user, searchTerm]);

  // --- Drag and Drop Handlers ---
  const handleDragStart = (e: React.DragEvent, id: string, type: 'venda' | 'indicacao') => {
    setDraggedItem({ id, type });
    e.dataTransfer.setData('text/plain', id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDrop = async (e: React.DragEvent, newStatus: string, type: 'venda' | 'indicacao') => {
    e.preventDefault();
    if (!draggedItem || draggedItem.type !== type) return;

    const collection = type === 'vendas' ? 'vendas' : 'indicacoes';
    try {
      await cloud.updateStatus(draggedItem.type === 'venda' ? 'vendas' : 'indicacoes', draggedItem.id, newStatus);
    } catch (err) {
      console.error("Erro ao mover item:", err);
    }
    setDraggedItem(null);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  // --- Helpers ---
  const toggleSelectVenda = (id: string) => {
    setSelectedVendas(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectIndicacao = (id: string) => {
    setSelectedIndicacoes(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const bulkDeleteVendas = async () => {
    if (!selectedVendas.length) return;
    if (confirm(`Excluir ${selectedVendas.length} registros de produção permanentemente?`)) {
      for (const id of selectedVendas) await cloud.apagar('vendas', id);
      setSelectedVendas([]);
    }
  };

  const bulkDeleteIndicacoes = async () => {
    if (!selectedIndicacoes.length) return;
    if (confirm(`Excluir ${selectedIndicacoes.length} leads permanentemente?`)) {
      for (const id of selectedIndicacoes) await cloud.apagar('indicacoes', id);
      setSelectedIndicacoes([]);
