             <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
               {usuarios.map(u => (
                 <div key={u.id} onClick={() => { setModalType('usuario'); setEditingItem(u); }} className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 border-l-8 border-l-red-600 hover:scale-[1.03] transition-all cursor-pointer">
                   <h4 className="text-[14px] font-black uppercase text-white mb-2">{u.nome}</h4>
                   <p className="text-[10px] text-gray-500 uppercase font-black">Setor: {u.setor}</p>
                   <div className="mt-4 inline-block bg-red-600/10 text-red-500 px-3 py-1 rounded-lg text-[11px] font-black">{u.comissao}% Comissão</div>
                 </div>
               ))}
             </div>
           </div>
        )}
        {activeSection === 'metas' && <div className="p-20 text-center opacity-30 font-black uppercase">Módulo de Metas em Manutenção</div>}
        {activeSection === 'lead-suhai-page' && <LeadSuhaiView />}
        {activeSection === 'configuracoes' && (
          <div className="animate-in fade-in duration-500 max-w-4xl mx-auto space-y-10">
            <div className="flex justify-between items-center">
              <h2 className="text-4xl font-black uppercase text-gray-300">Estrutura</h2>
              <button onClick={() => { setModalType('empresa'); setEditingItem(null); }} className="bg-white/5 border border-white/10 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-white hover:bg-white/10 transition-all">Nova Seguradora</button>
            </div>
            <div className="bg-[#111827] p-10 rounded-[3rem] border border-gray-800 shadow-xl">
              <h3 className="text-xl font-black uppercase text-blue-500 mb-8 tracking-tighter">Parceiros Cadastrados</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {empresas.map(emp => (
                  <div key={emp.id} className="bg-[#0f172a] p-6 rounded-2xl border border-gray-800 flex justify-between items-center group">
                    <span className="text-sm font-black uppercase text-white">{emp.nome}</span>
                    <button onClick={async () => { if(confirm("Remover?")) await cloud.apagar('empresas', emp.id!); }} className="text-red-500 opacity-0 group-hover:opacity-100 transition-all"><i className="fas fa-trash"></i></button>
                  </div>
                ))}
                {empresas.length === 0 && <p className="col-span-2 text-center text-gray-700 uppercase font-black py-10">Sem parceiros</p>}
              </div>
            </div>
          </div>
        )}
      </div>
      <ModalForm />
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta, Empresa } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);
  const [empresas, setEmpresas] = useState<Empresa[]>([]);

  // Selection State
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
  const [selectedIndicacoes, setSelectedIndicacoes] = useState<string[]>([]);

  // Modals
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | 'empresa' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);

  // Drag and Drop State (Mantido para compatibilidade)
  const [draggedItem, setDraggedItem] = useState<{ id: string, type: 'venda' | 'indicacao' } | null>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);
    const unsubEmpresas = cloud.subscribeEmpresas(setEmpresas);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
      unsubEmpresas();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => (u.login || '').toLowerCase() === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  // Funções de Movimentação Rápida por Seta
  const moveVenda = async (item: Venda, direction: 'left' | 'right') => {
    const currentIndex = VENDA_STATUS_MAP.indexOf(item.status);
    const nextIndex = direction === 'right' ? currentIndex + 1 : currentIndex - 1;
    if (nextIndex >= 0 && nextIndex < VENDA_STATUS_MAP.length) {
      await cloud.updateStatus('vendas', item.id!, VENDA_STATUS_MAP[nextIndex]);
    }
  };

  const moveIndicacao = async (item: Indicacao, direction: 'left' | 'right') => {
    const currentIndex = INDICACAO_STATUS_MAP.indexOf(item.status);
    const nextIndex = direction === 'right' ? currentIndex + 1 : currentIndex - 1;
    if (nextIndex >= 0 && nextIndex < INDICACAO_STATUS_MAP.length) {
      await cloud.updateStatus('indicacoes', item.id!, INDICACAO_STATUS_MAP[nextIndex]);
    }
  };

  // Filtros de busca robustos contra undefined
  const filteredVendas = useMemo(() => {
    let list = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      list = list.filter(v => 
        (v.cliente || '').toLowerCase().includes(lower) || 
        (v.vendedor || '').toLowerCase().includes(lower) ||
        (v.empresa || '').toLowerCase().includes(lower)
      );
    }
    return list;
  }, [vendas, user, searchTerm]);

  const filteredIndicacoes = useMemo(() => {
    let list = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      list = list.filter(i => 
        (i.cliente || '').toLowerCase().includes(lower) || 
        (i.veiculo || '').toLowerCase().includes(lower) ||
        (i.vendedor || '').toLowerCase().includes(lower)
      );
    }
    return list;
  }, [indicacoes, user, searchTerm]);

  // Drag and Drop (Fallback)
  const handleDragStart = (e: React.DragEvent, id: string, type: 'venda' | 'indicacao') => {
    setDraggedItem({ id, type });
    e.dataTransfer.setData('text/plain', id);
  };

  const handleDragOver = (e: React.DragEvent) => e.preventDefault();

  const handleDrop = async (e: React.DragEvent, newStatus: string, type: 'venda' | 'indicacao') => {
    e.preventDefault();
    const id = e.dataTransfer.getData('text/plain') || draggedItem?.id;
    if (!id || (draggedItem && draggedItem.type !== type)) return;
    await cloud.updateStatus(type === 'venda' ? 'vendas' : 'indicacoes', id, newStatus);
    setDraggedItem(null);
  };

  // --- Views ---

  const KanbanIndicacoes = () => (
    <div className="animate-in fade-in duration-300 h-full flex flex-col">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-black uppercase text-yellow-500 tracking-tighter">Leads</h2>
          <p className="text-[10px] font-bold text-gray-500 uppercase">Use as setas para mover rapidamente ou arraste</p>
        </div>
        <button onClick={() => { setModalType('indicacao'); setEditingItem(null); }} className="bg-yellow-500 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-black shadow-lg shadow-yellow-500/20">Novo Lead</button>
      </div>

      <div className="relative mb-6">
        <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-500"></i>
        <input 
          type="text" 
          placeholder="BUSCA LIVRE (NOME, VEÍCULO, VENDEDOR)..." 
          className="w-full bg-[#111827] border border-gray-800 rounded-2xl py-4 pl-12 pr-4 text-xs font-bold text-white outline-none focus:border-yellow-500 transition-all uppercase"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {INDICACAO_STATUS_MAP.map(status => (
          <div 
            key={status} 
            onDragOver={handleDragOver}
            onDrop={(e) => handleDrop(e, status, 'indicacao')}
            className="kanban-column bg-[#0f172a] rounded-[2.5rem] p-5 border border-gray-800 flex flex-col"
          >
            <h3 className="text-[10px] font-black uppercase text-gray-500 mb-6 text-center tracking-[0.2em]">{status}</h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
              {filteredIndicacoes.filter(i => i.status === status).map(i => (
                <div 
                  key={i.id} 
                  draggable
                  onDragStart={(e) => handleDragStart(e, i.id!, 'indicacao')}
                  className="group bg-[#111827] border border-gray-800 p-6 rounded-[2rem] border-l-4 border-l-yellow-500 hover:scale-[1.02] transition-all cursor-grab shadow-xl relative"
                >
                  <div className="flex justify-between items-start mb-2">
                    <h4 onClick={() => { setModalType('indicacao'); setEditingItem(i); }} className="text-[12px] font-black uppercase text-white cursor-pointer hover:text-yellow-500">{i.cliente}</h4>
                    <button onClick={async () => { if(confirm("Excluir?")) await cloud.apagar('indicacoes', i.id!); }} className="text-red-500/30 hover:text-red-500 transition-colors"><i className="fas fa-trash text-[10px]"></i></button>
                  </div>
                  <p className="text-[10px] text-gray-500 font-bold uppercase mb-4">{i.veiculo}</p>

                  <div className="flex justify-between items-center pt-3 border-t border-gray-800">
                    <button 
                      disabled={INDICACAO_STATUS_MAP.indexOf(i.status) === 0}
                      onClick={() => moveIndicacao(i, 'left')}
                      className="w-8 h-8 rounded-full bg-gray-800 flex items-center justify-center text-gray-400 hover:bg-yellow-500 hover:text-black disabled:opacity-0 transition-all"
                    >
                      <i className="fas fa-chevron-left text-[10px]"></i>
                    </button>

                    <span className="text-[9px] font-black uppercase text-gray-600">{i.vendedor}</span>

                    <button 
                      disabled={INDICACAO_STATUS_MAP.indexOf(i.status) === INDICACAO_STATUS_MAP.length - 1}
                      onClick={() => moveIndicacao(i, 'right')}
                      className="w-8 h-8 rounded-full bg-gray-800 flex items-center justify-center text-gray-400 hover:bg-yellow-500 hover:text-black disabled:opacity-0 transition-all"
                    >
                      <i className="fas fa-chevron-right text-[10px]"></i>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const KanbanVendas = () => (
    <div className="animate-in fade-in duration-300 h-full flex flex-col">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-black uppercase text-blue-500 tracking-tighter">Produção</h2>
          <p className="text-[10px] font-bold text-gray-500 uppercase">Setas laterais movem o registro instantaneamente</p>
        </div>
        <button onClick={() => { setModalType('venda'); setEditingItem(null); }} className="bg-blue-600 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-white shadow-lg shadow-blue-500/20">Lançar Venda</button>
      </div>

      <div className="relative mb-6">
        <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-500"></i>
        <input 
          type="text" 
          placeholder="PESQUISAR POR QUALQUER CAMPO..." 
          className="w-full bg-[#111827] border border-gray-800 rounded-2xl py-4 pl-12 pr-4 text-xs font-bold text-white outline-none focus:border-blue-500 transition-all uppercase"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="flex-1 flex gap-6 overflow-x-auto pb-6 scrollbar-thin">
        {VENDA_STATUS_MAP.map(status => (
          <div 
            key={status} 
            onDragOver={handleDragOver}
            onDrop={(e) => handleDrop(e, status, 'venda')}
            className="kanban-column bg-[#0f172a] rounded-[2.5rem] p-5 border border-gray-800 flex flex-col"
          >
            <h3 className="text-[10px] font-black uppercase text-gray-500 mb-6 text-center tracking-[0.2em]">{status}</h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
              {filteredVendas.filter(v => v.status === status).map(v => (
                <div 
                  key={v.id} 
                  draggable
                  onDragStart={(e) => handleDragStart(e, v.id!, 'venda')}
                  className="group bg-[#111827] border border-gray-800 p-5 rounded-[2rem] border-l-4 border-l-blue-600 hover:scale-[1.02] transition-all cursor-grab shadow-xl relative"
                >
                  <div className="flex justify-between items-start mb-1">
                    <h4 onClick={() => { setModalType('venda'); setEditingItem(v); }} className="text-[12px] font-black uppercase text-white cursor-pointer hover:text-blue-500">{v.cliente}</h4>
                    {v.suhai && <i className="fas fa-star text-green-500 text-[10px]"></i>}
                  </div>
                  <p className="text-[9px] text-gray-500 font-black uppercase mb-3">{v.empresa || 'Sem Empresa'}</p>

                  <div className="bg-[#0f172a] p-3 rounded-2xl mb-4 border border-gray-800 text-center shadow-inner">
                    <p className="text-[14px] font-black text-white">{FORMAT_BRL(v.valor)}</p>
                  </div>

                  <div className="flex justify-between items-center pt-2 border-t border-gray-800">
                    <button 
                      disabled={VENDA_STATUS_MAP.indexOf(v.status) === 0}
                      onClick={() => moveVenda(v, 'left')}
                      className="w-8 h-8 rounded-full bg-gray-800 flex items-center justify-center text-gray-400 hover:bg-blue-600 hover:text-white disabled:opacity-0 transition-all"
                    >
                      <i className="fas fa-chevron-left text-[10px]"></i>
                    </button>

                    <div className="text-center">
                       <p className="text-[7px] text-gray-500 uppercase font-black">Vendedor</p>
                       <p className="text-[9px] text-blue-400 font-black uppercase">{v.vendedor}</p>
                    </div>

                    <button 
                      disabled={VENDA_STATUS_MAP.indexOf(v.status) === VENDA_STATUS_MAP.length - 1}
                      onClick={() => moveVenda(v, 'right')}
                      className="w-8 h-8 rounded-full bg-gray-800 flex items-center justify-center text-gray-400 hover:bg-blue-600 hover:text-white disabled:opacity-0 transition-all"
                    >
                      <i className="fas fa-chevron-right text-[10px]"></i>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const Dashboard = () => {
    const today = new Date().setHours(0, 0, 0, 0);
    const vHoje = filteredVendas.filter(v => (v.dataCriacao || 0) >= today);
    const comissaoHoje = vHoje.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);

    return (
      <div className="animate-in fade-in duration-500">
        <h2 className="text-4xl font-black uppercase text-white tracking-tighter mb-10">Cockpit</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
          <div className="bg-[#111827] p-8 rounded-[2rem] border border-blue-900/30 shadow-2xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Vendas (Hoje)</p>
            <h2 className="text-6xl font-black text-white">{vHoje.length}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2rem] border border-green-900/30 shadow-2xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Comissão (Hoje)</p>
            <h2 className="text-6xl font-black text-green-500">{FORMAT_BRL(comissaoHoje)}</h2>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2rem] border border-gray-800 shadow-2xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Leads Ativos</p>
            <h2 className="text-6xl font-black text-white">{filteredIndicacoes.length}</h2>
          </div>
        </div>
      </div>
    );
  };

  const ModalForm = () => {
    const [vf, setVf] = useState<any>(editingItem || {});

    useEffect(() => {
      if (modalType === 'venda' && !editingItem && user) {
        setVf({ vendedor: user.nome, status: 'Fazer Vistoria', suhai: false, valor: 0, comissao_cheia: 0, comissao_vendedor: 0, empresa: '' });
      } else if (editingItem) {
        setVf(editingItem);
      }
    }, [modalType, editingItem, user]);

    if (!modalType) return null;

    const save = async (e: React.FormEvent) => {
      e.preventDefault();
      try {
        if (modalType === 'venda') await cloud.salvarVenda({ ...vf });
        if (modalType === 'indicacao') await cloud.salvarIndicacao({ ...vf });
        if (modalType === 'usuario') await cloud.salvarUsuario({ ...vf });
        if (modalType === 'empresa') await cloud.salvarEmpresa({ ...vf });
        setModalType(null);
      } catch (err) { alert("Erro ao salvar dados."); }
    };

    return (
      <div className="fixed inset-0 bg-black/95 backdrop-blur-xl flex items-center justify-center z-[500] p-4 animate-in fade-in duration-300">
        <div className="bg-[#111827] p-10 rounded-[3.5rem] w-full max-w-xl border border-gray-800 shadow-2xl overflow-y-auto max-h-[90vh] scrollbar-thin">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-2xl font-black uppercase text-white tracking-tighter">Gerenciar {modalType}</h3>
            <button onClick={() => setModalType(null)} className="text-gray-500 hover:text-white transition"><i className="fas fa-times text-xl"></i></button>
          </div>
          <form onSubmit={save} className="space-y-6">
            <input value={vf.cliente || vf.nome || ''} onChange={e => setVf({...vf, [modalType === 'usuario' || modalType === 'empresa' ? 'nome' : 'cliente']: e.target.value})} placeholder="NOME" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase focus:border-blue-500" required />
            <div className="flex gap-4 pt-8">
              <button type="button" onClick={() => setModalType(null)} className="flex-1 bg-gray-800 p-6 rounded-[2rem] font-black uppercase text-white">Cancelar</button>
              <button type="submit" className="flex-1 bg-blue-600 p-6 rounded-[2rem] font-black uppercase text-white">Salvar</button>
            </div>
          </form>
        </div>
      </div>
    );
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0b0f1a]">
        <div className="bg-[#111827] p-12 rounded-[3.5rem] shadow-2xl w-full max-w-md border border-gray-800 text-center">
          <h1 className="text-4xl font-black mb-1 uppercase tracking-tighter text-white font-mono">VM SEGUROS</h1>
          <p className="text-gray-500 text-[10px] mb-12 uppercase font-black tracking-[0.4em]">Cloud System</p>
          <div className="space-y-5">
            <input type="text" placeholder="LOGIN" className="w-full p-6 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold uppercase outline-none focus:border-blue-500" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} />
            <input type="password" placeholder="SENHA" className="w-full p-6 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold outline-none focus:border-blue-500" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} onKeyDown={e => e.key === 'Enter' && handleLogin()} />
            <button onClick={handleLogin} className="w-full bg-blue-600 hover:bg-blue-500 p-6 rounded-[2rem] font-black uppercase text-white transition-all shadow-2xl">Entrar</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1600px] mx-auto h-full p-2">
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'comissao' && <div className="p-10 text-white font-black uppercase">Módulo Financeiro</div>}
        {activeSection === 'cadastrar-indicacao' && <div className="p-10 text-white font-black uppercase">Distribuir Leads</div>}
        {activeSection === 'vendedores' && <div className="p-10 text-white font-black uppercase">Equipe</div>}
        {activeSection === 'metas' && <div className="p-10 text-white font-black uppercase">Metas</div>}
        {activeSection === 'lead-suhai-page' && <div className="p-10 text-white font-black uppercase">Suhai Gold</div>}
        {activeSection === 'configuracoes' && <div className="p-10 text-white font-black uppercase">Configurações</div>}
      </div>
      <ModalForm />
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta, Empresa } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);
  const [empresas, setEmpresas] = useState<Empresa[]>([]);

  // Selection State
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
