  const LeadSuhaiView = () => {
    const suhaiRecords = filteredVendas.filter(v => v.suhai && v.status === 'Pagamento Efetuado');
    const totalComissao = suhaiRecords.reduce((acc, v) => acc + (user?.isAdmin ? (v.comissao_cheia || 0) : (v.comissao_vendedor || 0)), 0);
    const totalPremio = suhaiRecords.reduce((acc, v) => acc + (v.valor || 0), 0);

    return (
      <div className="animate-in fade-in duration-500">
        <h2 className="text-4xl font-black uppercase text-green-500 mb-10 tracking-tighter">Suhai Gold - Pagos</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-10">
           <div className="bg-[#111827] p-8 rounded-[2rem] border border-green-500/30 shadow-2xl">
              <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Comissão Suhai</p>
              <h2 className="text-5xl font-black text-green-500">{FORMAT_BRL(totalComissao)}</h2>
           </div>
           <div className="bg-[#111827] p-8 rounded-[2rem] border border-blue-500/30 shadow-2xl">
              <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Prêmio Total</p>
              <h2 className="text-5xl font-black text-blue-500">{FORMAT_BRL(totalPremio)}</h2>
           </div>
        </div>
        <div className="bg-[#111827] rounded-[2.5rem] border border-gray-800 overflow-hidden shadow-2xl">
           <table className="w-full text-left">
              <thead className="bg-[#0f172a] text-gray-400 text-[10px] uppercase font-black">
                 <tr>
                    <th className="p-6">Vendedor</th>
                    <th className="p-6">Cliente</th>
                    <th className="p-6">Prêmio</th>
                    <th className="p-6">Comissão</th>
                    <th className="p-6 text-center">Status</th>
                 </tr>
              </thead>
              <tbody className="text-xs font-bold uppercase">
                 {suhaiRecords.map(v => (
                    <tr key={v.id} className="border-b border-gray-800 hover:bg-gray-800/20">
                       <td className="p-6 text-blue-400">{v.vendedor}</td>
                       <td className="p-6 text-white">{v.cliente}</td>
                       <td className="p-6 text-gray-400">{FORMAT_BRL(v.valor)}</td>
                       <td className="p-6 text-green-500 font-black">{FORMAT_BRL(user?.isAdmin ? v.comissao_cheia : v.comissao_vendedor)}</td>
                       <td className="p-6 text-center"><span className="text-[9px] bg-green-500/10 text-green-500 px-3 py-1 rounded-full">PAGO</span></td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>
      </div>
    );
  };

  const Financeiro = () => {
    const concluido = filteredVendas.filter(v => v.status === 'Pagamento Efetuado');
    const totalComissao = concluido.reduce((a, b) => a + Number(user?.isAdmin ? (b.comissao_cheia || 0) : (b.comissao_vendedor || 0)), 0);

    return (
      <div className="animate-in fade-in duration-500">
        <h2 className="text-4xl font-black uppercase text-green-500 mb-10 tracking-tighter">Financeiro</h2>
        <div className="bg-[#111827] p-12 rounded-[3rem] border border-green-900/30 text-center mb-10 shadow-2xl">
          <p className="text-gray-500 text-[11px] font-black uppercase mb-2">Total Sua Parte (Vendas Pagas)</p>
          <h2 className="text-7xl font-black text-green-500">{FORMAT_BRL(totalComissao)}</h2>
        </div>
        <div className="bg-[#111827] rounded-[2rem] border border-gray-800 overflow-hidden shadow-xl">
          <table className="w-full text-left">
            <thead className="bg-[#1e293b] text-gray-400 text-[10px] uppercase font-black">
              <tr>
                <th className="p-6">Data</th>
                <th className="p-6">Cliente</th>
                <th className="p-6">Prêmio</th>
                <th className="p-6">Comissão</th>
              </tr>
            </thead>
            <tbody className="text-xs font-bold uppercase">
              {concluido.map(v => (
                <tr key={v.id} className="border-b border-gray-800 hover:bg-gray-800/20">
                  <td className="p-6 text-gray-500">{new Date(v.dataCriacao || 0).toLocaleDateString()}</td>
                  <td className="p-6 text-white">{v.cliente}</td>
                  <td className="p-6 text-gray-400">{FORMAT_BRL(v.valor)}</td>
                  <td className="p-6 font-black text-green-500">{FORMAT_BRL(user?.isAdmin ? v.comissao_cheia : v.comissao_vendedor)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  const FormLead = () => (
    <div className="max-w-2xl mx-auto animate-in zoom-in-95 duration-500">
      <div className="bg-[#111827] p-12 rounded-[3rem] border border-gray-800 shadow-2xl">
        <h2 className="text-2xl font-black uppercase text-yellow-500 mb-10 text-center">Distribuir Lead</h2>
        <form onSubmit={async (e) => {
          e.preventDefault();
          const f = (e.target as any);
          await cloud.salvarIndicacao({
            cliente: f.cliente.value,
            tel: f.tel.value,
            veiculo: f.veiculo.value,
            vendedor: f.vendedor.value,
            suhai: f.suhai.checked,
            status: 'NOVA INDICAÇÃO',
            info: f.info.value,
            dataCriacao: Date.now()
          } as any);
          alert('Lead enviado!');
          f.reset();
        }} className="space-y-5">
          <input name="cliente" placeholder="NOME DO CLIENTE" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase focus:border-blue-500" required />
          <input name="tel" placeholder="WHATSAPP" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none focus:border-blue-500" required />
          <input name="veiculo" placeholder="VEÍCULO" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase focus:border-blue-500" required />
          <select name="vendedor" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase" required>
             {usuarios.map(u => <option key={u.id} value={u.nome}>{u.nome}</option>)}
          </select>
          <textarea name="info" placeholder="NOTAS ADICIONAIS" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none h-32 uppercase"></textarea>
          <div className="flex items-center gap-4">
            <input type="checkbox" name="suhai" className="w-6 h-6 accent-green-500" />
            <label className="text-xs font-black uppercase text-green-500">Marcar como Suhai Gold</label>
          </div>
          <button type="submit" className="w-full bg-yellow-500 p-6 rounded-[2rem] font-black uppercase text-black hover:scale-105 transition-all shadow-xl">Confirmar Envio</button>
        </form>
      </div>
    </div>
  );

  const VendedoresView = () => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-10">
        <h2 className="text-4xl font-black uppercase text-red-500">Equipe</h2>
        <button onClick={() => { setModalType('usuario'); setEditingItem(null); }} className="bg-red-600 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-white">Novo Usuário</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {usuarios.map(u => (
          <div key={u.id} onClick={() => { setModalType('usuario'); setEditingItem(u); }} className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 border-l-8 border-l-red-600 hover:scale-[1.03] transition-all cursor-pointer shadow-xl">
            <h4 className="text-[14px] font-black uppercase text-white mb-2">{u.nome}</h4>
            <p className="text-[10px] text-gray-500 uppercase font-black">Setor: {u.setor}</p>
            <div className="mt-4 inline-block bg-red-600/10 text-red-500 px-3 py-1 rounded-lg text-[11px] font-black">{u.comissao}% Comissão</div>
          </div>
        ))}
      </div>
    </div>
  );

  const MetasView = () => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-10">
        <h2 className="text-4xl font-black uppercase text-blue-400">Metas</h2>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {usuarios.map(u => {
           const existingMeta = metas.find(m => m.vendedor === u.nome);
           const displayMeta = existingMeta || { meta_salario: 0, meta_premio: 0, meta_qtd: 0 };
           return (
             <div key={u.id} onClick={() => { setModalType('meta'); setEditingItem(existingMeta ? existingMeta : { vendedor: u.nome }); }} className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 hover:border-blue-500 transition-all cursor-pointer shadow-xl">
               <h4 className="text-[14px] font-black uppercase text-blue-400 mb-6">{u.nome}</h4>
               <div className="space-y-4">
                 <div className="flex justify-between text-[10px] font-black uppercase text-gray-500"><span>Meta Salarial</span><span className="text-white">{FORMAT_BRL(displayMeta.meta_salario)}</span></div>
                 <div className="flex justify-between text-[10px] font-black uppercase text-gray-500"><span>Meta Prêmio</span><span className="text-white">{FORMAT_BRL(displayMeta.meta_premio)}</span></div>
                 <div className="flex justify-between text-[10px] font-black uppercase text-gray-500"><span>Quantidade</span><span className="text-white">{displayMeta.meta_qtd}</span></div>
               </div>
             </div>
           );
        })}
      </div>
    </div>
  );

  const ConfiguracoesView = () => (
    <div className="animate-in fade-in duration-500 max-w-4xl mx-auto space-y-10">
      <div className="flex justify-between items-center">
        <h2 className="text-4xl font-black uppercase text-gray-300 tracking-tighter">Configurações</h2>
        <button onClick={() => { setModalType('empresa'); setEditingItem(null); }} className="bg-white/5 border border-white/10 px-8 py-3 rounded-2xl font-black text-[11px] uppercase text-white hover:bg-white/10">Nova Seguradora</button>
      </div>
      <div className="bg-[#111827] p-10 rounded-[3rem] border border-gray-800 shadow-xl">
        <h3 className="text-xl font-black uppercase text-blue-500 mb-8">Parceiros Cadastrados</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {empresas.map(emp => (
            <div key={emp.id} className="bg-[#0f172a] p-6 rounded-2xl border border-gray-800 flex justify-between items-center group">
              <span className="text-sm font-black uppercase text-white">{emp.nome}</span>
              <button onClick={async () => { if(confirm("Remover?")) await cloud.apagar('empresas', emp.id!); }} className="text-red-500 opacity-0 group-hover:opacity-100 transition-all"><i className="fas fa-trash"></i></button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const ModalForm = () => {
    const [vf, setVf] = useState<any>(editingItem || {});

    useEffect(() => {
      if (modalType === 'venda' && !editingItem && user) {
        setVf({ vendedor: user.nome, status: 'Fazer Vistoria', suhai: false, valor: 0, comissao_cheia: 0, comissao_vendedor: 0, empresa: '' });
      } else if (editingItem) {
        setVf(editingItem);
      }
    }, [modalType, editingItem, user]);

    if (!modalType) return null;

    const save = async (e: React.FormEvent) => {
      e.preventDefault();
      try {
        if (modalType === 'venda') await cloud.salvarVenda({ ...vf });
        if (modalType === 'indicacao') await cloud.salvarIndicacao({ ...vf });
        if (modalType === 'usuario') await cloud.salvarUsuario({ ...vf });
        if (modalType === 'empresa') await cloud.salvarEmpresa({ ...vf });
        if (modalType === 'meta') await cloud.salvarMeta({ ...vf });
        setModalType(null);
      } catch (err) { alert("Erro ao salvar."); }
    };

    return (
      <div className="fixed inset-0 bg-black/95 backdrop-blur-xl flex items-center justify-center z-[500] p-4 animate-in fade-in duration-300">
        <div className="bg-[#111827] p-10 rounded-[3.5rem] w-full max-w-xl border border-gray-800 shadow-2xl overflow-y-auto max-h-[90vh] scrollbar-thin">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-2xl font-black uppercase text-white tracking-tighter">Gerenciar {modalType}</h3>
            <button onClick={() => setModalType(null)} className="text-gray-500 hover:text-white transition"><i className="fas fa-times text-xl"></i></button>
          </div>
          <form onSubmit={save} className="space-y-6">
            {(modalType === 'usuario' || modalType === 'empresa' || modalType === 'indicacao' || modalType === 'venda') && (
              <input value={vf.cliente || vf.nome || ''} onChange={e => setVf({...vf, [modalType === 'usuario' || modalType === 'empresa' ? 'nome' : 'cliente']: e.target.value})} placeholder="NOME" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase focus:border-blue-500" required />
            )}

            {modalType === 'usuario' && (
              <div className="space-y-4">
                 <input value={vf.login || ''} onChange={e => setVf({...vf, login: e.target.value})} placeholder="LOGIN" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase" required />
                 <input type="password" value={vf.senha || ''} onChange={e => setVf({...vf, senha: e.target.value})} placeholder="SENHA" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" required />
                 <select value={vf.setor || 'VENDEDOR'} onChange={e => setVf({...vf, setor: e.target.value})} className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase">
                   <option value="VENDEDOR">VENDEDOR</option>
                   <option value="ADMIN">ADMIN</option>
                 </select>
                 <input type="number" value={vf.comissao || 0} onChange={e => setVf({...vf, comissao: Number(e.target.value)})} placeholder="COMISSÃO (%)" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
              </div>
            )}

            {modalType === 'meta' && (
              <div className="space-y-4">
                 <p className="text-xs font-black uppercase text-blue-400">Vendedor: {vf.vendedor}</p>
                 <input type="number" value={vf.meta_salario || 0} onChange={e => setVf({...vf, meta_salario: Number(e.target.value)})} placeholder="META SALARIAL (R$)" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
                 <input type="number" value={vf.meta_premio || 0} onChange={e => setVf({...vf, meta_premio: Number(e.target.value)})} placeholder="META PRÊMIO (R$)" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
                 <input type="number" value={vf.meta_qtd || 0} onChange={e => setVf({...vf, meta_qtd: Number(e.target.value)})} placeholder="META QUANTIDADE" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
              </div>
            )}

            {modalType === 'venda' && (
              <div className="space-y-4">
                 <input value={vf.tel || ''} onChange={e => setVf({...vf, tel: e.target.value})} placeholder="WHATSAPP" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
                 <select value={vf.empresa || ''} onChange={e => setVf({...vf, empresa: e.target.value})} className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none uppercase">
                   <option value="">SELECIONE SEGURADORA</option>
                   {empresas.map(e => <option key={e.id} value={e.nome}>{e.nome}</option>)}
                 </select>
                 <div className="grid grid-cols-2 gap-4">
                    <input type="number" step="0.01" value={vf.valor || 0} onChange={e => setVf({...vf, valor: Number(e.target.value)})} placeholder="PRÊMIO (R$)" className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
                    <input type="number" step="0.01" value={vf.comissao_cheia || 0} onChange={e => setVf({...vf, comissao_cheia: Number(e.target.value)})} placeholder="C. CHEIA (R$)" className="p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
                 </div>
                 <input type="number" step="0.01" value={vf.comissao_vendedor || 0} onChange={e => setVf({...vf, comissao_vendedor: Number(e.target.value)})} placeholder="SUA PARTE (R$)" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
              </div>
            )}

            <div className="flex gap-4 pt-8">
              <button type="button" onClick={() => setModalType(null)} className="flex-1 bg-gray-800 p-6 rounded-[2rem] font-black uppercase text-white hover:bg-gray-700 transition-all">Cancelar</button>
              <button type="submit" className="flex-1 bg-blue-600 p-6 rounded-[2rem] font-black uppercase text-white shadow-xl shadow-blue-600/20 hover:scale-105 transition-all">Salvar Alterações</button>
            </div>
          </form>
        </div>
      </div>
    );
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0b0f1a]">
        <div className="bg-[#111827] p-12 rounded-[3.5rem] shadow-2xl w-full max-w-md border border-gray-800 text-center animate-in zoom-in-95 duration-700">
          <h1 className="text-4xl font-black mb-1 uppercase tracking-tighter text-white font-mono">VM SEGUROS</h1>
          <p className="text-gray-500 text-[10px] mb-12 uppercase font-black tracking-[0.4em]">Elite Cloud System</p>
          <div className="space-y-5">
            <input type="text" placeholder="LOGIN" className="w-full p-6 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold uppercase outline-none focus:border-blue-500" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} />
            <input type="password" placeholder="SENHA" className="w-full p-6 rounded-2xl border border-gray-800 bg-[#0f172a] text-white text-sm font-bold outline-none focus:border-blue-500" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} onKeyDown={e => e.key === 'Enter' && handleLogin()} />
            <button onClick={handleLogin} className="w-full bg-blue-600 hover:bg-blue-500 p-6 rounded-[2rem] font-black uppercase text-white transition-all shadow-2xl">Acessar CRM</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1600px] mx-auto h-full p-2">
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'comissao' && <Financeiro />}
        {activeSection === 'cadastrar-indicacao' && <FormLead />}
        {activeSection === 'vendedores' && <VendedoresView />}
        {activeSection === 'metas' && <MetasView />}
        {activeSection === 'lead-suhai-page' && <LeadSuhaiView />}
        {activeSection === 'configuracoes' && <ConfiguracoesView />}
        {activeSection === 'links-uteis' && (
          <div className="animate-in fade-in duration-500 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
             <a href="https://suhai.com.br" target="_blank" className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 flex items-center justify-between hover:border-green-500 transition-all">
                <span className="font-black uppercase text-white">Suhai Seguradora</span>
                <i className="fas fa-external-link-alt text-gray-600"></i>
             </a>
             <a href="https://vmsolutions.com.br" target="_blank" className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 flex items-center justify-between hover:border-blue-500 transition-all">
                <span className="font-black uppercase text-white">Portal VM Solutions</span>
                <i className="fas fa-external-link-alt text-gray-600"></i>
             </a>
          </div>
        )}
      </div>
      <ModalForm />
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta, Empresa } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);
  const [empresas, setEmpresas] = useState<Empresa[]>([]);

  // Selection State for Bulk Actions
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
