          <div className="animate-in fade-in duration-500 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
             <a href="https://suhai.com.br" target="_blank" className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 flex items-center justify-between hover:border-green-500 transition-all">
