                 <input type="number" value={vf.comissao || 0} onChange={e => setVf({...vf, comissao: Number(e.target.value)})} placeholder="COMISSÃO (%)" className="w-full p-5 bg-[#0f172a] border border-gray-800 rounded-2xl text-white font-bold outline-none" />
