        setVf({ vendedor: user.nome, status: modalType === 'venda' ? 'Fazer Vistoria' : 'NOVA INDICAÇÃO', suhai: false, valor: 0, comissao_cheia: 0, comissao_vendedor: 0, empresa: '', tel: '', cliente: '', veiculo: '', info: '' });
