                      <div className="h-2 bg-[#0f172a] rounded-full overflow-hidden border border-gray-800">
                        <div className="h-full bg-blue-600 shadow-[0_0_10px_rgba(37,99,235,0.5)] transition-all" style={{ width: `${percent}%` }}></div>
                      </div>
