              <div className="space-y-6">
                {INDICACAO_STATUS_MAP.map(status => {
                  const myLeads = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
                  const count = myLeads.filter(i => i.status === status).length;
